export type FeatureStoreSeedItem = {
    itemKey: string;
    slug: string;
    name: string;
    description?: string;
    itemType:
        | "dashboard-feature"
        | "workspace-app"
        | "agent-builder"
        | "shared-block-set"
        | "template"
        | "external-app";
    featureKey?: string;
    route?: string;
    builderMode?: "json_blocks" | "custom_code";
    scope: "workspace-local" | "workspace-shared" | "general/shared" | "tenant-shared";
    status: "draft" | "planned" | "ready";
    source: "seed";
    icon?: string;
    tags?: string[];
    requiredRoles?: string[];
    grantedSkillKeys?: string[];
    runtimeDomains?: string[];
    config?: Record<string, unknown>;
    preview?: {
        headline?: string;
        summary?: string;
        bullets?: string[];
        accent?: string;
        previewType?: "card" | "builder" | "template";
        config?: Record<string, unknown>;
    };
};

function featureItem(input: Omit<FeatureStoreSeedItem, "itemType" | "source">): FeatureStoreSeedItem {
    return {
        ...input,
        itemType: "dashboard-feature",
        source: "seed",
    };
}

